"use strict";dotclear.ready(()=>{if(!dotclear.debug){const e=document.querySelector("#header")?document.querySelector("#header"):document.querySelector("h1");e?.addEventListener("dblclick",t=>{if(t.target!==e)return;let{theme:d}=document.documentElement.dataset;null!=d&&""!==d||(d=globalThis.matchMedia("(prefers-color-scheme: dark)")?"dark":"light"),document.documentElement.dataset.theme="dark"===d?"light":"dark"})}});
